class Solution {
public:
    int jump(vector<int>& nums) {
        int maxPos = 0, n = nums.size(), end = 0, step = 0; // end=当前步数可达的右边界，maxPos=下一步可达的最远位置
        for (int i = 0; i < n - 1; ++i) {
            if (maxPos >= i) {
                maxPos = max(maxPos, i + nums[i]);
                if (i == end) { // 当前这一层走完，必须再跳一步
                    end = maxPos;
                    ++step;
                }
            }
        }
        return step;
    }
};
